import{_ as t,c as l,o as h,a5 as r,j as a}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.58：TUI 交互优化","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.58.md","filePath":"changelog/v1.1.58.md","lastUpdated":1772014034000}'),i={name:"changelog/v1.1.58.md"};function d(n,e,o,s,c,b){return h(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="v1-1-58-tui-交互优化" tabindex="-1">v1.1.58：TUI 交互优化 <a class="header-anchor" href="#v1-1-58-tui-交互优化" aria-label="Permalink to “v1.1.58：TUI 交互优化”">​</a></h1><p><strong>发布日期</strong>：2026年2月11日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新 <strong>优化了终端界面（TUI）的交互体验</strong>，支持 Ctrl+C 关闭对话框、不同模式显示不同输入提示、分享链接可重复复制。</p><hr><h2 id="新功能-ctrl-c-关闭对话框" tabindex="-1">新功能：Ctrl+C 关闭对话框 <a class="header-anchor" href="#新功能-ctrl-c-关闭对话框" aria-label="Permalink to “新功能：Ctrl+C 关闭对话框”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>在 TUI 中，现在可以用 <strong>Ctrl+C 关闭各种对话框</strong>，不用再找 Escape 键了。</p><h3 id="为什么重要" tabindex="-1">为什么重要？ <a class="header-anchor" href="#为什么重要" aria-label="Permalink to “为什么重要？”">​</a></h3><p>之前关闭对话框只能按 Escape，现在 Ctrl+C 也能用，更符合直觉。</p><hr><h2 id="新功能-模式专属输入提示" tabindex="-1">新功能：模式专属输入提示 <a class="header-anchor" href="#新功能-模式专属输入提示" aria-label="Permalink to “新功能：模式专属输入提示”">​</a></h2><h3 id="这次更新了什么-1" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-1" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>输入框的提示文字现在会根据当前模式变化，告诉你该输入什么。</p><h3 id="效果示例" tabindex="-1">效果示例 <a class="header-anchor" href="#效果示例" aria-label="Permalink to “效果示例”">​</a></h3><table tabindex="0"><thead><tr><th>模式</th><th>提示文字</th></tr></thead><tbody><tr><td>默认模式</td><td>「问我任何问题...」</td></tr><tr><td>代码模式</td><td>「描述你想要的功能...」</td></tr><tr><td>计划模式</td><td>「描述你的项目需求...」</td></tr></tbody></table><p>这样你就能清楚地知道在当前模式下应该怎么提问。</p><hr><h2 id="新功能-分享链接可重复复制" tabindex="-1">新功能：分享链接可重复复制 <a class="header-anchor" href="#新功能-分享链接可重复复制" aria-label="Permalink to “新功能：分享链接可重复复制”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>使用 <code>/share</code> 命令分享会话后，如果想再次复制链接，需要重新生成。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p><code>/share</code> 命令现在保持可用，可以随时复制已生成的分享链接，无需重复生成。</p><hr><h2 id="改进-home-界面自适应" tabindex="-1">改进：Home 界面自适应 <a class="header-anchor" href="#改进-home-界面自适应" aria-label="Permalink to “改进：Home 界面自适应”">​</a></h2><h3 id="之前的问题-1" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-1" aria-label="Permalink to “之前的问题”">​</a></h3><p>在终端高度受限的情况下，Home 界面的文字可能会显示异常。</p><h3 id="现在的情况-1" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-1" aria-label="Permalink to “现在的情况”">​</a></h3><p>修复了在高度受限的终端中，Home 界面文字显示损坏的问题。</p><hr><h2 id="问题修复-桌面端" tabindex="-1">问题修复：桌面端 <a class="header-anchor" href="#问题修复-桌面端" aria-label="Permalink to “问题修复：桌面端”">​</a></h2><h3 id="子会话通知" tabindex="-1">子会话通知 <a class="header-anchor" href="#子会话通知" aria-label="Permalink to “子会话通知”">​</a></h3><p>现在子会话（Fork 出来的会话）也能显示通知了。</p><h3 id="终端缓冲区" tabindex="-1">终端缓冲区 <a class="header-anchor" href="#终端缓冲区" aria-label="Permalink to “终端缓冲区”">​</a></h3><p>终端 PTY 缓冲区现在可以在会话之间正确保留，切换会话不会丢失之前的输出。</p><h3 id="终端大小调整" tabindex="-1">终端大小调整 <a class="header-anchor" href="#终端大小调整" aria-label="Permalink to “终端大小调整”">​</a></h3><p>修复了桌面应用中终端大小调整的问题。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>经常用 TUI</td><td>✅ 升级</td></tr><tr><td>需要分享会话</td><td>✅ 升级</td></tr><tr><td>只用桌面版</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',42),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),r('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="tui-终端界面" tabindex="-1">TUI（终端界面） <a class="header-anchor" href="#tui-终端界面" aria-label="Permalink to “TUI（终端界面）”">​</a></h3><ul><li>支持 Ctrl+C 关闭对话框</li><li>保持 /share 命令可用以复制已有链接</li><li>添加模式专属输入提示</li><li>修复高度受限终端中 Home 界面文字损坏</li></ul><h3 id="desktop-桌面应用" tabindex="-1">Desktop（桌面应用） <a class="header-anchor" href="#desktop-桌面应用" aria-label="Permalink to “Desktop（桌面应用）”">​</a></h3><ul><li>回退 WSL 后端模式功能</li><li>子会话启用通知</li><li>终端 PTY 缓冲区在会话间正确保留</li><li>修复终端大小调整功能</li></ul><h3 id="社区贡献" tabindex="-1">社区贡献 <a class="header-anchor" href="#社区贡献" aria-label="Permalink to “社区贡献”">​</a></h3><ul><li>@kitlangton：TUI 交互优化（Ctrl+C 关闭对话框、模式提示、Home 界面修复、分享链接）</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const _=t(i,[["render",d]]);export{m as __pageData,_ as default};
